INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('856b591e-08b3-40ec-b505-cb3b143293bb', 'Bröd ( kaek ) 15:-', '1-brod-kaek', 'Det är vanligt att njuta av Kunafa inuti bröd. Man lägger sirap i brödet och fyller det sedan med Kunafa. Välj hur många bröd du vill ha tillsammans med din Kunafa beställning.', 'https://mormorskunafa.se/wp-content/uploads/2023/01/Malmlo_Kaak-brod-4-scaled-500x667-1.jpg', 1500, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('f05b6a24-7b90-4dfb-8f2f-be67a475cbfa', 'Mormors Box – En Gåva av äkta Smaker', 'mormors-box-en-gava-av-akta-smaker', 'Upptäck <strong>Mormors Box</strong>, en lyxig samling av handgjorda orientaliska bakverk, perfekta som present eller för att bjuda dina gäster på något riktigt speciellt.\\r\\n\\r\\n🧡 <strong>Vad finns i boxen?</strong>\\r\\n✔ <strong>Baklava Pistage</strong> – Krispig filodeg fylld med finaste pistagenötter och söt sirap.\\r\\n✔ <strong>Baklava Valnöt</strong> – En klassisk favorit med spröda lager och rik valnötsfyllning.\\r\\n✔ <strong>Maamoul Mad Pistage</strong> – En mjuk och smakrik kaka fylld med pistagenötter.\\r\\n✔ <strong>Maamoul Mad Valnöt</strong> – En mjuk och smakrik kaka fylld med valnötter.\\r\\n✔ <strong>Turkisk Baklava Pistage</strong> – Extra krämig baklava fylld med premium finmald pistage.\\r\\n✔ <strong>Harise</strong> – En saftig mannagrynskaka med perfekt balans av sötma.\\r\\n\\r\\n📦 <strong>Vikt:</strong> 1 kg', 'https://mormorskunafa.se/wp-content/uploads/2025/02/yujjyjj.jpg', 0, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('1ae3fd7a-0042-4220-b330-b27b3147a0a6', 'Baklawa Pistage 89 kr', 'baklawa-pistage', '<h3 data-start=\\"243\\" data-end=\\"293\\"><strong data-start=\\"247\\" data-end=\\"293\\">Baklawa Pistage – ren smak, utan överdrift</strong></h3>\\r\\n<p data-start=\\"295\\" data-end=\\"379\\">Det första du märker är balansen.<br data-start=\\"328\\" data-end=\\"331\\" />Inte för söt. Inte för tung. Bara precis rätt.</p>\\r\\n<p data-start=\\"381\\" data-end=\\"647\\">Vi valde att hålla igen på sirapen  för att lyfta fram det som verkligen betyder något:<br data-start=\\"469\\" data-end=\\"472\\" />De finaste pistagenötterna, den handrullade filodegen, och det äkta smöret som binder allt samman.<br data-start=\\"570\\" data-end=\\"573\\" /><strong>Resultatet?</strong> En baklawa du kan njuta av om och om igen, utan att tröttna.</p>\\r\\n<p data-start=\\"649\\" data-end=\\"814\\">Här handlar det inte om att överväldiga  utan om att förfina.<br data-start=\\"711\\" data-end=\\"714\\" />Varje tugga är tydlig, krispig och rik på smak. En elegant tolkning av ett älskat klassiskt bakverk.</p>', 'https://mormorskunafa.se/wp-content/uploads/2025/05/91.png', 8900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('37b8b656-2604-4ca6-9745-e0d6f52338c1', 'Krispigkunafa 149kr - كنافة خشنة', 'krispig-kunafa', '<h3><strong>Där festen börjar… med ett ljud</strong></h3>\\r\\nDet finns ljud som fastnar i minnet, skratt från köket, skedar som rör i kastruller, och Mormors röst som fyller hela hemmet med värme.Minnen tar dig till barndomen eller till speciella högtider eller en vanlig dag som blev något speciellt. Men en sak minns du: hur allt stannade upp för en stund – när doften av smör, sirap och rostad deg spred sig i huset.\\r\\n\\r\\nDet är här vår historia börjar, med en hyllning till tradition, från generation till generation.\\r\\n<h3><strong>Krispig kunafa som förr, men ännu bättre</strong></h3>\\r\\nVi har bevarat det som gjorde den klassiska kunafan älskad:\\r\\nden gyllene ytan, de rostade trådarna, det ljuva lagret av ost eller Ashta,\\r\\noch den perfekt balanserade sirapen – men vi har lagt till något mer:\\r\\nvår tid, vår precision, vår passion. Krispigkunafa, bakad på låg värme och hög känsla. Det är kärlek i varje lager. Och det är resultatet av år av erfarenhet och kärlek till det vi gör.\\r\\n\\r\\n&nbsp;\\r\\n<h3><strong>Ett ljud, en doft, en smak… en upplevelse</strong></h3>\\r\\n<h3><strong>Vem är den för?</strong></h3>\\r\\n– För dig som växte upp med \\"den riktiga kunafan\\"\\r\\n– För dig som vill bjuda på något som hörs innan det smakas\\r\\n– För dig som vet att det finns smaker som för folk närmare\\r\\n<h3><strong>För vi vet första intrycket börjar redan vid förpackningen</strong></h3>\\r\\nVi valde en design som speglar vad som finns inuti:\\r\\nstolthet, elegans och en doft av tradition.\\r\\n\\r\\nEn stilren låda i djupa färger,\\r\\nAllt är genomtänkt:\\r\\n\\r\\nDet är mer än en efterrätt.\\r\\nDet är en historia du får smaka.\\r\\nBeställ nu!\\r\\n\\r\\nMöjlig notering: Krispigheten kan försvinna efter en dag.\\r\\n\\r\\n.في كل لحظة تبدأ الحفلات, والذكريات تُصنع\\r\\nهناك أصوات تظل في الذاكرة، تلك التي تتسلل إلى القلب قبل الأذن\\r\\nضحكات المطبخ، ورفرفة الملاعق بين القدور، و\\r\\nذلك الصوت الأول، الصوت المميز، عندما يقضم أحدهم أول قضمة من الكنافة المقرمشة الطازجة\\r\\n\\r\\nربما كانت أيام الطفولة، ربما كان العيد، أو مجرد يوم عادي أصبح غير عادي في لحظة واحدة\\r\\nلكن، مهما كان، هناك شيء واحد يتبقى: اللحظة التي يتوقف فيها الزمن\\r\\nعندما تنتشر رائحة السمنة، القطر، واالكنافة المحمصة في كل مكان\\r\\n\\r\\n!هنا تبدأ قصتنا\\r\\n\\r\\nقصتنا التي تحتفل بالتقاليد وباللحظات التي تملأ الطاولة بصوانٍ كبيرة وحبّ جارف\\r\\nوباللحظة التي تسمع فيها \\"لحظة، خلينا نلتقط صورة أولاً!\\"\\r\\n\\r\\nالكنافة المقرمشة – كما كانت دائمًا، ولكن مع لمسة جديدة\\r\\nلقد حافظنا على كل شيء جعل الكنافة محبوبة في قلوب الجميع\\r\\nالطبقة الذهبية المقرمشة، والخيوط المحمصة، والقشطة أو الجبن\\r\\nوالشراب المتوازن بشكل مثالي – لكننا أضفنا لمسة خاصة\\r\\n!رؤيتنا، دقتنا، وشغفنا\\r\\n\\r\\n.كنافة, تُخبز على نارهادئة، ولكن بحب وعناية\\r\\n.إنها  نتيجة سنوات من الخبرة والتفاني في ما نقدمه\\r\\n\\r\\nالصوت، الرائحة، الطعم... تجربة لا تُنسى\\r\\nالكنافة المقرمشة ليست مجرد حلوى.\\r\\nإنها تقليد ينبض بالحياة في كل مرة تقدم فيها\\r\\nهي لحظة تتلاقى فيها العيون، تمتد فيها الأيدي\\r\\nوتصبح الطاولة أكثر من مجرد مكان للطعام – بل هي مكان للتواصل والاحتفال\\r\\n\\r\\n:لأننا نعلم جيدًا – الانطباع الأول يبدأ من التغليف\\r\\nاخترنا تصميمًا يعكس ما بداخل العلبة\\r\\nفخر، أناقة، ورائحة تقليدية أصيلة\\r\\n\\r\\nعلبة انيقة بألوان عميقة\\r\\n\\r\\n.ومحتوى يقرمش بانتظار أن يتذوقه الجميع كل تفصيلة في مكانها\\r\\n\\r\\nاطلبها الان!\\r\\n<p data-start=\\"157\\" data-end=\\"210\\"><em data-start=\\"173\\" data-end=\\"208\\">ملاحظة: قد تختفي القرمشة بعد يوم.</em></p>\\r\\n<p data-start=\\"212\\" data-end=\\"340\\" data-is-last-node=\\"\\" data-is-only-node=\\"\\"></p>', 'https://mormorskunafa.se/wp-content/uploads/2025/05/5.png', 14900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('77048580-fd68-454d-b34b-395b351a96d4', 'Finmaldkunafa 149kr - كنافة ناعمة', 'finmald-kunafa', '<h3><strong>Berättelsen börjar här...</strong></h3>\\r\\nKanske har du haft en dag då du längtade efter värme. Efter ett ögonblick av stillhet som kramar om dig varsamt. En smak som, tar dig tillbaka till barndomens trygghet. I just det ögonblicket finns det inget som slår en varm Kunafa som smälter i munnen, som en viskning från en svunnen tid.\\r\\n\\r\\n&nbsp;\\r\\n\\r\\nFinmaldkunafa är en fin strimlad deg blandad med äkta arabiskt smör <em>Ghee</em>, fylld med krämig ost, ringlad med lätt sockerlag och toppad med pistage nötter  som en gyllene slutpunkt på varje berättelse.\\r\\n\\r\\n&nbsp;\\r\\n<h3><strong>En produkt som förändrar allt\\r\\n</strong></h3>\\r\\nKunafa är inte bara en efterrätt, den är en ritual, ett ögonblick, en hel upplevelse som börjar med doften och slutar med ett leende.\\r\\nDet är smaken av hem, av familj, av kvällar där man samlas runt en plåt och någon ropar:\\r\\n”Passa på Kunafan innan den tar slut!”\\r\\nRedan från första tuggan känner du skillnaden\\r\\nen skillnad skapad av kvalitet, känsla och kärlek i varje lager.\\r\\n<h3><strong>Vem passar den för?</strong></h3>\\r\\n– För Smakälskare som vill ha en smakupplevelse att minnas.\\r\\n– För dem som föredrar det mjuka framför det krispiga – något som smälter i hjärtat.\\r\\n– Som en gåva fylld med omtanke och värme  för vår lena Kunafa är ett ätbart kärleksbrev.\\r\\n<h3><strong>Smaken börjar redan med Ögonen...</strong></h3>\\r\\nKunafan behövde egentligen inte en elegant låda, men vi tror att varje detalj berättar en historia. Därför skapade vi en förpackning som omfamnar produkten, precis som första ögonkastet gör. En varm, stilren låda med exklusiv känsla. Att öppna den känns som att öppna en gåva du inte visste att du behövde.Inuti – mjuka skydd som bevarar värmen och håller kunafan som en liten juvel. Ett lätt pistage strössel ovanpå, och små gyllene gafflar som gör varje tugga till en ceremoni.\\r\\n\\r\\nربما مرّ عليك يوم شعرت فيه بحاجة إلى دفء، إلى لحظة هدوء تحضنك بلطف، إلى طعم يعيدك لطفولتك دون أن تدري... في تلك اللحظة، لا شيء ينجح كما تنجح لقمة كنافة ناعمة تذوب في فمك، كأنها همسة من زمن جميل\\r\\n\\r\\n...لما كانت كل بداية حلوة\\r\\n\\r\\nفي بداياتنا، تعودنا على الكنافة المقرمشة، لكن هناك من كان يبحث عن ملمس مختلف، عن تجربة أكثر نعومة ودفئاً... ومن هنا وُلدت الكنافة الناعمة: عجينة ناعمة ممزوجة بالسمن العربي الأصيل، محشوة بجبنة ذائبة، تُسقى بالقطر الخفيف وتُزيَّن برشة فستق .حلبي وكأنها لمسة ذهبية تختم كل قصة\\r\\n\\r\\n...منتج واحد\\r\\n\\r\\nيغيّر كل شيء الكنافة الناعمة ليست فقط حلواً، بل هي طقس، لحظة، تجربة كاملة تبدأ من الرائحة وتنتهي بابتسامة. هي قطعة تحكي عن دفء البيت، عن صواني الأمهات، وعن سهرات العائلة على وقع \\"خلي عينك عالكنافة\\". من أول لقمة، ستشعر أن هناك فرقاً… فرق تصنعه الجودة، الملمس، والنية الطيبة في كل طبقة.\\r\\n\\r\\nلمن هذا المنتج؟\\r\\n\\r\\n.للذوّاقة الذين يبحثون عن نكهة تأسرهم وتبقى في ذاكرتهم\\r\\n.لمن يحبون المفاجآت الناعمة، التي لا تُقرمش بل تُذوّب القلب\\r\\n.لهدية تحمل معاني الدفء والاهتمام، لأن الكنافة الناعمة هي رسالة حب تؤكل\\r\\n\\r\\n&nbsp;\\r\\n\\r\\n...ولأن الذوق يبدأ من العلبة\\r\\n\\r\\nلم تكن الكنافة الناعمة بحاجة إلى أكثر من علبة بسيطة، لكننا آمنّا أن كل تفصيلة يجب أن تحكي قصتها الخاصة. لذلك صممنا تغليفًا يعانق المنتج كما تعانقه النظرة الأولى. علبة أنيقة بلونٍ دافئ يوحي بالفخامة والدفء، تُفتح كأنك تفتح هدية لا تعرف كم تحتاجها .حتى تتذوقها. في الداخل،  ناعمة تحفظ الحرارة وتحتضن الكنافة كأنها جوهرة. رشة فستق تعانق السطح،  تجعل كل لقمة وكأنها طقس من طقوس العيد. على الغلاف، لا تجد إلا ما تحتاج: اسم يلامس القلب، وشعار صُنع ليُؤكل، ويُتذك', 'https://mormorskunafa.se/wp-content/uploads/2025/05/6.png', 14900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('054b4adf-4da3-42c0-aa9b-b939023aafad', 'Baklawa Valnöt 69 kr', 'baklawa-valnot', '500gram blir ca. 16-20 små bitar', 'https://mormorskunafa.se/wp-content/uploads/2025/05/B-A-K-L-A-W-A-2.png', 6900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('6c1efa0e-149c-4259-9bd0-f85fd35f4b62', 'Halawet El Jibn 125 kr', 'ostkaka', '<p data-start=\\"49\\" data-end=\\"456\\"><strong data-start=\\"49\\" data-end=\\"81\\">En söt och krämig delikatess</strong><br data-start=\\"81\\" data-end=\\"84\\" />Halawet El Jibn är en himmelsk arabisk efterrätt som kombinerar den lena smaken av ost med en söt, mjuk deg. Fylld med en krämig blandning av ost och socker, rullas denna dessert till perfektion och toppas ofta med pistage eller sockerlag för extra smak. Den har en balanserad konsistens och är både söt och lätt, vilket gör den till en fantastisk avslutning på en måltid.</p>\\r\\n<p data-start=\\"458\\" data-end=\\"623\\"><strong data-start=\\"458\\" data-end=\\"470\\">För vem?</strong><br data-start=\\"470\\" data-end=\\"473\\" />För dig som älskar söta, ostbaserade desserter, för dig som söker en smakfull tradition och för dig som vill unna dig något riktigt mjukt och delikat.</p>\\r\\n<p data-start=\\"625\\" data-end=\\"678\\" data-is-last-node=\\"\\" data-is-only-node=\\"\\"><strong data-start=\\"625\\" data-end=\\"678\\" data-is-last-node=\\"\\">Mer än en efterrätt – en himmelsk smakupplevelse.</strong></p>', 'https://mormorskunafa.se/wp-content/uploads/2025/05/4.png', 7900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('fc469599-82e8-4ea3-aa18-0436bc2a2afd', 'Ashta Baklawa 149 kr', 'baklawa-ashta', '<p data-start=\\"51\\" data-end=\\"427\\"><strong data-start=\\"51\\" data-end=\\"80\\">En lyxig fusion av smaker</strong><br data-start=\\"80\\" data-end=\\"83\\" />Ashta Baklawa är en härlig kombination av den klassiska baklawan med en rik och krämig ashta (arabiskt grädde) i mitten. Den smöriga, spröda degen omsluter det lena lagret av ashta och ger en perfekt balans mellan sött och krämigt. Toppad med finhackade pistage och bakad till perfektion, erbjuder denna baklawa en oemotståndlig smakupplevelse.</p>\\r\\n<p data-start=\\"429\\" data-end=\\"638\\"><strong data-start=\\"429\\" data-end=\\"441\\">För vem?</strong><br data-start=\\"441\\" data-end=\\"444\\" />För dig som vill njuta av en sofistikerad twist på en klassisk favorit, för dig som älskar den perfekta blandningen av smördeg och krämig fyllning, och för dig som söker något unikt och delikat.</p>\\r\\n<p data-start=\\"640\\" data-end=\\"700\\" data-is-last-node=\\"\\" data-is-only-node=\\"\\"><strong data-start=\\"640\\" data-end=\\"700\\" data-is-last-node=\\"\\">Mer än bara en efterrätt – en smak av tradition och lyx.</strong></p>', 'https://mormorskunafa.se/wp-content/uploads/2025/05/3.png', 14900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('94fd4a72-2685-4bc4-8813-0f5e5eaa4a1c', 'Mad bel Ashta', 'mad-bel-ashta-%d9%85%d8%b9%d9%85%d9%88%d9%84-%d9%85%d8%af-%d8%a8%d8%a7%d9%84%d9%82%d8%b4%d8%b7%d8%a9', '<strong data-start=\\"54\\" data-end=\\"71\\">Mad bel Ashta</strong><br data-start=\\"71\\" data-end=\\"74\\" />En utsökt, krämig dessert fylld med den traditionella arabisk grädden \\"ashta\\". Denna läckra efterrätt kombinerar den lena smaken av ashta med smördeg, vilket skapar en perfekt balans av sötma och krämighet. Toppad med finhackad pistage och lätt bakad till en gyllene färg, erbjuder Mad bel Ashta en oförglömlig smakupplevelse som tar dig på en resa genom den arabiska matkulturen. En perfekt avslutning på en måltid eller som en söt stund att njuta av när helst.', 'https://mormorskunafa.se/wp-content/uploads/2025/05/Mamoul-3.png', 7900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('c005c8af-3f2e-401c-923f-7dac0f682cda', 'Mormorsbox - BaklawaMix 299 kr', 'mormorsbox-mix', 'Upptäck <strong>Mormors Box</strong>, en lyxig samling av handgjorda orientaliska bakverk, perfekta som present eller för att bjuda dina gäster på något riktigt speciellt.\\r\\n\\r\\n🧡 <strong>Vad finns i boxen?</strong>\\r\\n✔ <strong>Baklava Pistage</strong> – Krispig filodeg fylld med finaste pistagenötter och söt sirap.\\r\\n✔ <strong>Baklava Valnöt</strong> – En klassisk favorit med spröda lager och rik valnötsfyllning.\\r\\n✔ <strong>Maamoul Mad Pistage</strong> – En mjuk och smakrik kaka fylld med pistagenötter.\\r\\n✔ <strong>Maamoul Mad Valnöt</strong> – En mjuk och smakrik kaka fylld med valnötter.\\r\\n✔ <strong>Turkisk Baklava Pistage</strong> – Extra krämig baklava fylld med premium finmald pistage.\\r\\n✔ <strong>Harise</strong> – En saftig mannagrynskaka med perfekt balans av sötma.\\r\\n\\r\\n📦 <strong>Vikt:</strong> 1 kg', 'https://mormorskunafa.se/wp-content/uploads/2025/02/yujjyjj.jpg', 29900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('6312f48a-b156-431b-9f6d-103cc30bc9f8', 'Mamoul Pistage 179 kr', 'mamoul-pistage-179-kr', NULL, 'https://mormorskunafa.se/wp-content/uploads/2026/01/ChatGPT-Image-27-jan.-2026-23_22_03.png', 6900, NULL, 'instock', NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `image_url`, `price_ore`, `stock_quantity`, `stock_status`, `sku`) VALUES ('9e6d210b-8637-4deb-889c-0726060288aa', 'Pistagemix 499kr', 'pistagemix', '<p data-start=\\"112\\" data-end=\\"304\\"><strong data-start=\\"112\\" data-end=\\"146\\">Upptäck vår Baklawa Pistagemix</strong> – en exklusiv samling handgjorda baklawabitar fyllda med premium pistage. Perfekt som lyxig gåva eller för att imponera på gäster vid speciella tillfällen 💚</p>\\r\\n<p data-start=\\"306\\" data-end=\\"665\\">🧡 <strong data-start=\\"309\\" data-end=\\"331\\">Vad finns i boxen?</strong><br data-start=\\"331\\" data-end=\\"334\\" />✔ <strong data-start=\\"336\\" data-end=\\"355\\">Fågelbo Pistage</strong> – Tunna, krispiga trådar av deg fyllda med generöst med pistage.<br data-start=\\"420\\" data-end=\\"423\\" />✔ <strong data-start=\\"425\\" data-end=\\"445\\">Röd</strong> <strong data-start=\\"425\\" data-end=\\"445\\">Baloriye Pistage</strong> – Spröd och elegant baklawa med rik pistagefyllning.<br data-start=\\"577\\" data-end=\\"580\\" />✔ <strong data-start=\\"582\\" data-end=\\"614\\">Vit Baloriye Baklawa Pistage</strong> – Extra len och lyxig variant med finmald pistage.</p>\\r\\n<p data-start=\\"667\\" data-end=\\"713\\">📦 <strong data-start=\\"670\\" data-end=\\"679\\">Vikt:</strong> 1350 gram<br data-start=\\"689\\" data-end=\\"692\\" />💰 <strong data-start=\\"695\\" data-end=\\"704\\">Pris:</strong> 499 kr</p>\\r\\n<p data-start=\\"715\\" data-end=\\"793\\">En pistagedröm i varje tugga – bakad med kärlek enligt traditionella recept 💫</p>', 'https://mormorskunafa.se/wp-content/uploads/2026/01/IMG_2011.jpg', 49900, NULL, 'instock', NULL);